import { Link, useLocation, useNavigate } from 'react-router-dom';

function AdminSidebar() {
  const location = useLocation();
  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem('user') || '{}');
  const isActive = (path) => location.pathname === path;

  const menuItems = [
    { path: '/admin', icon: '📊', label: 'Over View' },
    { path: '/admin/create-event', icon: '➕', label: 'Create Events' },
    { path: '/admin/manage-events', icon: '📝', label: 'Manage Events' },
    { path: '/admin/bookings', icon: '🎫', label: 'All Bookings' },
  ];

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    navigate('/login');
  };

  return (
    <aside style={{
      width: '220px', minHeight: '100vh',
      background: 'linear-gradient(180deg, #2d1b69 0%, #1e1b4b 100%)',
      display: 'flex', flexDirection: 'column', flexShrink: 0
    }}>
      {/* Logo */}
      <div style={{ padding: '1.5rem', borderBottom: '1px solid rgba(255,255,255,0.1)' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '1rem' }}>
          <div style={{
            background: 'linear-gradient(135deg, #a78bfa, #7c3aed)',
            width: '32px', height: '32px', borderRadius: '8px',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            fontSize: '16px', fontWeight: 'bold', color: 'white'
          }}>E</div>
          <div>
            <div style={{ color: 'white', fontWeight: '700', fontSize: '0.9rem' }}>EventEase</div>
            <div style={{ color: '#a78bfa', fontSize: '0.7rem' }}>Admin</div>
          </div>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', background: 'rgba(255,255,255,0.08)', padding: '8px 12px', borderRadius: '10px' }}>
          <div style={{ width: '28px', height: '28px', background: 'linear-gradient(135deg, #a78bfa, #7c3aed)', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '12px' }}>👤</div>
          <div>
            <div style={{ color: 'white', fontSize: '0.8rem', fontWeight: '600' }}>{user.name}</div>
            <div style={{ color: '#a78bfa', fontSize: '0.65rem' }}>Administrator</div>
          </div>
        </div>
      </div>

      {/* Menu */}
      <nav style={{ flex: 1, padding: '1rem 0.75rem' }}>
        {menuItems.map(item => (
          <Link key={item.path} to={item.path} style={{
            display: 'flex', alignItems: 'center', gap: '10px',
            padding: '10px 14px', borderRadius: '10px', marginBottom: '4px',
            textDecoration: 'none', fontSize: '0.85rem', fontWeight: '500',
            background: isActive(item.path) ? 'linear-gradient(135deg, #7c3aed, #a78bfa)' : 'transparent',
            color: isActive(item.path) ? 'white' : 'rgba(255,255,255,0.6)',
            transition: 'all 0.2s',
            boxShadow: isActive(item.path) ? '0 4px 15px rgba(124,58,237,0.4)' : 'none'
          }}>
            <span>{item.icon}</span>
            <span>{item.label}</span>
          </Link>
        ))}
      </nav>

      {/* Footer */}
      <div style={{ padding: '0.75rem', borderTop: '1px solid rgba(255,255,255,0.1)' }}>
        <Link to="/home" style={{
          display: 'flex', alignItems: 'center', gap: '8px',
          padding: '8px 14px', borderRadius: '8px', color: 'rgba(255,255,255,0.5)',
          textDecoration: 'none', fontSize: '0.8rem', marginBottom: '4px'
        }}>🏠 Home</Link>
        <button onClick={handleLogout} style={{
          width: '100%', display: 'flex', alignItems: 'center', gap: '8px',
          padding: '8px 14px', borderRadius: '8px', color: '#f87171',
          background: 'transparent', border: 'none', cursor: 'pointer', fontSize: '0.8rem'
        }}>🚪 Logout</button>
      </div>
    </aside>
  );
}
export default AdminSidebar;
